CREATE TABLE transfer_job_errors (job_id VARCHAR(36) NOT NULL, sequence_no INT UNSIGNED NOT NULL, source_row INT UNSIGNED NOT NULL, field_key VARCHAR(255) NOT NULL, error_code VARCHAR(64) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, error_message VARCHAR(1000) NOT NULL, PRIMARY KEY (job_id,sequence_no), KEY idx_transfer_job_errors_order (job_id,source_row,field_key,error_code,sequence_no), CONSTRAINT fk_transfer_job_errors_job FOREIGN KEY (job_id) REFERENCES transfer_jobs (job_id) ON DELETE CASCADE, CONSTRAINT chk_transfer_job_errors_row CHECK (source_row BETWEEN 1 AND 100001), CONSTRAINT chk_transfer_job_errors_code CHECK (error_code REGEXP _ascii'^[a-z][a-z0-9_]*$')) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
